class Solution:
    def distanceTraveled(self, mainTank: int, additionalTank: int) -> int:
        distance = 0
        while mainTank > 0:
            # Consume 5 liters of fuel
            used = min(5, mainTank)
            distance += used * 10
            mainTank -= used

            # Check if we can transfer fuel
            if used == 5 and additionalTank > 0:
                mainTank += 1
                additionalTank -= 1

        return distance
